import sys
import math

N = int(input())
ages = [int(input()) for k in range(N)]

uc = 0.0
adult_count = 0

for age in ages:
    if age >= 14:
        if adult_count == 0:
            uc += 1.0
        else:
            uc += 0.5
        adult_count += 1
    else:
        uc += 0.3
print(round(uc, 1))
